INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-eng-moex-00783', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能試驗基準規定，防焰物品或其材料之防焰性能有關用語定義，下列敘述何者錯誤？', '["餘燃時間係指自點火時間終了起，試樣之火焰繼續燃燒之時間", "碳化面積係指試樣經加熱燃燒後碳化部分之面積", "碳化距離係指試樣經加熱燃燒後碳化部分之最大長度", "接焰次數係指試樣經接觸火源至完全熔融燃燒時之接觸火源次數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00784', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法，六類公共危險物品製造場所或一般處 理場所之構造規定，下列何者錯誤？', '["應設於建築物之地面層或地上層", "牆壁、樑、柱、地板及樓梯，應以不燃材料建造；外牆有延燒之虞者，除出入口外，不得設置其 他開口，且應採用防火構造", "窗戶及出入口應設置至少30分鐘防火時效之防火門窗；牆壁開口有延燒之虞者，應設置至少1小 時防火時效之常時關閉式防火門", "窗戶及出入口裝有玻璃時，應使用強化玻璃"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00785', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法規定，毀損供消防使用之蓄、供水設備或消防、救護設備者，除處 3 年以下有期徒刑或拘 役外，還有何種可能處罰？', '["得併科新臺幣6千元以上3萬元以下罰金", "另併科新臺幣6千元以上3萬元以下罰鍰", "得易科新臺幣6千元以上3萬元以下罰金", "得易科新臺幣6千元以上3萬元以下罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00786', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則總則編，若干類型建築物應檢具防火避難綜合檢討報告書及評定書，或建築物防火 避難性能設計計畫書及評定書，經中央主管建築機關認可。下列建築物何者不在規定範圍內？', '["供建築物使用類組B-2組（商場百貨）使用之總樓地板面積達3萬平方公尺以上之建築物", "高度達25層或90公尺以上之高層建築物，但僅供建築物用途類組H-2組（住宅）使用者，不受 此限", "具有高度超過20公尺以上且面積達500平方公尺以上之挑空中庭或挑高樓層建築物", "與地下公共運輸系統相連接之地下街或地下商場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00787', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防設備師及消防設備士管理辦法規定，消防設備師及消防設備士應遵守事項，下列何者錯誤？', '["消防設備師及消防設備士，應受各級消防機關之監督", "消防設備師及消防設備士執行業務時，應攜帶資格證件", "自取得證書日起每3年應接受講習一次或取得累計積分達160分以上之訓練證明文件", "執行業務，應備業務登記簿，以書面簿冊形式或電子檔案方式，並應妥善保存至少 3 年，以備各 級消防機關之查核"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00788', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能認證實施要點，有關消防法第11條第1項所稱地毯之規定，下列何者錯誤？', '["地毯包括手工毯、滿舖地毯、方塊地毯、人工草皮與面積2平方公尺以上之門墊等", "防焰性能試驗之產品試樣規格1平方公尺以上", "地毯等地坪舖設物防焰標示方法限採鑲釘方式", "凡毛簇形式、毛高或底材不同者，則應分別送驗，依試驗結果分別取得不同之試驗合格號碼"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00789', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法，公共危險物品六類物品製造場所，其 外牆或相當於該外牆之設施外側，與廠區外鄰近場所之安全距離規定，下列何者錯誤？', '["與古蹟之距離，應在50公尺以上", "與博物館、美術館之距離，應在30公尺以上", "與加油站、加氣站、天然氣儲槽、可燃性高壓氣體儲槽之距離，應在20公尺以上", "與電壓超過3萬5千伏特之高架電線之距離，應在5公尺以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00790', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依可燃性高壓氣體儲存場所防爆牆設置基準及可燃性高壓氣體儲存場所防護牆設置基準，有關防爆 牆與防護牆之規定，下列何者錯誤？', '["防爆牆長度應超過設置方位儲存場所建築物牆面長度，防護牆則無此規定", "防爆牆與防護牆之構造皆分為鋼筋混凝土製、混凝土空心磚製及鋼板製等 3 種，且防護牆厚度較 防爆牆厚度大，另防護牆應對被波及處之耐火及延燒應具有充分阻絕效果，而防爆牆強度應能承 受可能預料之氣體爆炸衝擊", "防爆牆與防護牆之設置皆應與各設備保持適當距離，且防爆牆不得妨礙火災時之滅火行動，防護 牆不得使洩漏之氣體滯留或妨礙日常作業", "防爆牆與防護牆之耐風壓力，皆應依建築技術規則建築構造編之相關規定辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00791', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法，下列用語定義，何者錯誤？', '["第三類公共危險物品指發火性液體、發火性固體及禁水性物質", "在常用溫度下或溫度在攝氏15度時，表壓力達每平方公分2公斤以上或0.2百萬帕斯卡（MPa）以上 之壓縮乙炔氣屬可燃性高壓氣體之一", "公共危險物品販賣裝於容器之六類物品，其數量達管制量15倍以上，未達40倍之場所，稱為第 二種販賣場所", "儲槽係純供灌裝可燃性高壓氣體之移動式高壓容器"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00792', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編，下列有關緊急用昇降機之規定，何者錯誤？', '["應有緊急電源之照明設備並設置消防栓、出水口、排煙設備、緊急電源插座等消防設備", "每座昇降機間之樓地板面積不得小於10平方公尺且在避難層之位置，自昇降機出口或昇降機間之 出入口至通往戶外出入口之步行距離不得大於40公尺", "應有能使設於各層機間及機廂內之昇降控制裝置暫時停止作用，並將機廂呼返避難層或其直上層、 下層之特別呼返裝置（一次消防）", "應設有使機廂門維持開啟狀態仍能昇降之裝置（二次消防）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
